#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<ll, ll>PII
using namespace std;
CI MAXN=2e3+50;
int ans[MAXN][MAXN],n;
void f(int size,int x,int y)
{
	if(size==1)
	{
		ans[x][y]=true;
		return;
	}
	int half=size>>1;
	f(half,x,y+half);
	f(half,x+half,y);
	f(half,x+half,y+half);
}
int main(void){
	scanf("%d",&n);
	f(1<<n,1,1);
	for(int i=1;i<=1<<n;++i)
	{
		for(int j=1;j<=1<<n;++j)
		{
			printf("%d ",ans[i][j]);
		}
		puts("");
	}
	return false;
}
